output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?attendance WHERE {
  ?game wdt:P31 wd:Q11517200 .
  {
    ?game wdt:P95 wd:Q334634 ; wdt:P96 wd:Q650840
  } UNION {
    ?game wdt:P95 wd:Q650840 ; wdt:P96 wd:Q334634
  }
  .
  ?game wdt:P372 ?series .
  ?series wdt:P31 wd:Q1363275 .
  ?game wdt:P1110 ?attendance
}
ORDER BY DESC(?attendance)
LIMIT 1

